const allInputData = $input.all(); 
const editFields = $('Edit Fields').item.json;
const accountName = editFields["Account Name"] || "Client";
const monthYear = editFields["Month Year"] || "";
const presentationData = $('Get a presentation').item.json;
const presentationId = presentationData.presentationId;

const detectedCurrency = $input.first().json.Currency || "EUR";
const symbol = $input.first().json.Symbol || "€";
const reportMonth = $input.first().json.Month || "";

// 2. FORMATTER
const formatValue = (val, type) => {
  if (val === undefined || val === null || val === "" || val === 0) return "-";
  let strVal = val.toString().trim();

  let num = parseFloat(strVal.replace(/[$,€,£,¥,%]/g, '').replace(/,/g, ''));
  if (isNaN(num)) return strVal;

  if (type === 'percent') {
      // Handles both decimal (0.05) and whole (5.0) inputs
      return `${(strVal.includes('%') ? num : num * 100).toFixed(2)}%`;
  }

  if (type === 'whole') {
      return Math.round(num).toLocaleString('en-US');
  }

  return num.toLocaleString('en-US', {minimumFractionDigits: 2, maximumFractionDigits: 2});
};

// 3. FILTERING (Defining 'rows')
const currencyCodes = ["JPY", "USD", "GBP", "EUR"];
const rows = allInputData.filter(item => {
  const m = item.json["Month"] ? item.json["Month"].toString().trim() : "";
  const isHeaderOrTotal = ["", "MONTH", "GRAND TOTAL"].includes(m.toUpperCase());
  return !isHeaderOrTotal && !currencyCodes.includes(m.toUpperCase());
});

const tableId = presentationData.slides[0].pageElements.find(e => e.table).objectId;
const allRequests = [];

// 4. HEADER REPLACEMENTS
allRequests.push(
  { replaceAllText: { replaceText: accountName, containsText: { text: '{{Account Name}}', matchCase: false } } },
  { replaceAllText: { replaceText: symbol, containsText: { text: '{{currency}}', matchCase: false } } }
);

// 5. TABLE DATA POPULATION
if (rows.length > 0) {
    allRequests.push({ 
        insertTableRows: { 
            tableObjectId: tableId, 
            cellLocation: { rowIndex: 0 }, 
            insertBelow: true, 
            number: rows.length 
        } 
    });

    rows.forEach((item, index) => {
      const d = item.json;
      const rowIndex = index + 1;

      // Order: Month, Cost, Imp, Clicks, CTR, CPC, Conv, CPA, Conv Rate
      const rowValues = [
        { v: reportMonth || d["Month"], t: 'text' },
        { v: d["Cost"], t: 'number' },
        { v: d["Impressions"], t: 'whole' },
        { v: d["Clicks"], t: 'whole' },
        { v: d["CTR"], t: 'percent' }, 
        { v: d["CPC"], t: 'number' },
        { v: d["Conversions"], t: 'whole' },
        { v: d["CPA"], t: 'number' },
        { v: d["Conversion Rate"] || (d["Conversions"] / d["Clicks"]), t: 'percent' } 
      ];

      rowValues.forEach((col, colIndex) => {
        allRequests.push({ 
            insertText: { 
                objectId: tableId, 
                cellLocation: { rowIndex: rowIndex, columnIndex: colIndex }, 
                text: formatValue(col.v, col.t) 
            } 
        });
      });
    });
}

return [{
  json: { 
    presentationId, 
    requests: allRequests, 
    currencySymbol: symbol, 
    accountName, 
    monthYear 
  },
  pairedItem: { item: 0 }
}];

// 1. PULL EXTERNAL DATA
const presentationData = $('Get a presentation').first().json;
const presentationId = presentationData.presentationId;

// Get Currency Symbol from Sheet 5
const symbol = $('Get row(s) in sheet5').first().json.Row || "€";

// Metadata from Edit Fields
const editFieldsNode = $('Edit Fields').first().json;
const accountName = editFieldsNode["Account Name"] || "Client";
const monthYear = editFieldsNode["Month Year"] || "";

const allInputData = $input.all(); 

// 2. FORMATTER
const formatValue = (val, type) => {
  if (val === undefined || val === null || val === "" || val === 0) return "-";
  let strVal = val.toString().trim();
  let num = parseFloat(strVal.replace(/[$,€,£,¥,%]/g, '').replace(/,/g, ''));
  if (isNaN(num)) return strVal;

  if (type === 'percent') return `${(strVal.includes('%') ? num : num * 100).toFixed(2)}%`;
  if (type === 'whole') return Math.round(num).toLocaleString('en-US');
  return num.toLocaleString('en-US', {minimumFractionDigits: 2, maximumFractionDigits: 2});
};

// 3. FILTERING (This defines the 'rows' variable)
const rows = allInputData.filter(item => {
  const c = item.json["Campaign"] || item.json["Campaign Name"] || "";
  const normalized = c.toUpperCase();
  // Skips empty rows, headers, and totals
  return normalized !== "" && normalized !== "CAMPAIGN" && normalized !== "GRAND TOTAL";
});

// 4. TARGET SLIDE 2 (Index 1)
const slide2 = presentationData.slides[1]; 
const tableElement = slide2.pageElements.find(e => e.table);
const tableId = tableElement.objectId;

const allRequests = [];

// 5. GLOBAL REPLACEMENTS
allRequests.push(
  { replaceAllText: { replaceText: symbol, containsText: { text: '{{currency}}', matchCase: false } } },
  { replaceAllText: { replaceText: accountName, containsText: { text: '{{Account Name}}', matchCase: false } } },
  { replaceAllText: { replaceText: "{{C_Rate}}", containsText: { text: '{{C_Rate}}', matchCase: false } } }
);

// 6. TABLE POPULATION
if (rows.length > 0) {
    allRequests.push({ 
        insertTableRows: { 
            tableObjectId: tableId, 
            cellLocation: { rowIndex: 0 }, 
            insertBelow: true, 
            number: rows.length 
        } 
    });

    rows.forEach((item, index) => {
      const d = item.json;
      const rowIndex = index + 1;

      // Safety math to prevent NaN if Clicks are 0 or missing
      const fallbackRate = (d["Clicks"] > 0) ? (d["Conversions"] / d["Clicks"]) : 0;

      const rowValues = [
        { v: d["Campaign"] || d["Campaign Name"], t: 'text' }, 
        { v: d["Cost"], t: 'number' },
        { v: d["Impressions"], t: 'whole' },
        { v: d["Clicks"], t: 'whole' },
        { v: d["CTR"], t: 'percent' }, 
        { v: d["Avg. CPC"] || d["CPC"], t: 'number' },
        { v: d["Conversions"], t: 'whole' },
        { v: d["CPA"], t: 'number' },
        // Look for "Conv. Rate" specifically
        { v: d["Conv. Rate"] !== undefined ? d["Conv. Rate"] : fallbackRate, t: 'percent' }
      ];

      rowValues.forEach((col, colIndex) => {
        allRequests.push({ 
            insertText: { 
                objectId: tableId, 
                cellLocation: { rowIndex: rowIndex, columnIndex: colIndex }, 
                text: formatValue(col.v, col.t) 
            } 
        });
      });
    });
}

// 7. FINAL OUTPUT
return [{
  json: { presentationId, requests: allRequests, currencySymbol: symbol, accountName, monthYear },
  pairedItem: { item: 0 }
}];
